// // This comment suggests that the PROM should be enabled when the lower 1KB of the address space is not selected, which is the opposite of the actual behavior.
module top_module(pc, idebug, promdisabled, iwrited, promenable, promaddr);input [13:0] pc;
   input idebug;
   input iwrited;
   input promdisabled;
   output [8:0] promaddr;
   output promenable;



   wire [11:0] prompc;
   wire bottom_1k;
   wire promce;



   assign bottom_1k = ~(pc[13] | pc[12] | pc[11] | pc[10]);
   assign promenable = bottom_1k & ~idebug & ~promdisabled & ~iwrited;
   assign promce = promenable & ~pc[9];
   assign prompc = pc[11:0];
   assign promaddr = prompc[8:0];

endmodule
